class Solution:
    def maxProfit(self, k: int, prices):
        n = len(prices)
        if n == 0:
            return 0
        if k >= n // 2:
            profit = 0
            for i in range(1, n):
                if prices[i] > prices[i-1]:
                    profit += prices[i] - prices[i-1]
            return profit
        dp = [[0] * n for _ in range(k + 1)]
        for i in range(1, k + 1):
            for j in range(1, n):
                dp[i][j] = dp[i][j-1]
                for m in range(j):
                    dp[i][j] = max(dp[i][j], prices[j] - prices[m] + dp[i-1][m])
        return dp[k][n-1]

