                    profit += prices[i] - prices[i-1]
            return profit
        dp = [[0] * n for _ in range(k + 1)]
        for i in range(1, k + 1):
            best = -prices[0]
            for j in range(1, n):
                dp[i][j] = max(dp[i][j-1], prices[j] + best)
                best = max(best, dp[i-1][j] - prices[j])
        return dp[k][n-1]

