var maxProfit = function(k, prices) {
    const n = prices.length;
    if (n === 0) return 0;
    if (k >= Math.floor(n / 2)) {
        let profit = 0;
        for (let i = 1; i < n; i++) {
            if (prices[i] > prices[i-1]) profit += prices[i] - prices[i-1];
        }
        return profit;
    }
    const dp = Array.from({length: k + 1}, () => new Array(n).fill(0));
    for (let i = 1; i <= k; i++) {
        let best = -prices[0];
        for (let j = 1; j < n; j++) {
            dp[i][j] = Math.max(dp[i][j-1], prices[j] + best);
            best = Math.max(best, dp[i-1][j] - prices[j]);
        }
    }
    return dp[k][n-1];
};
